```javascript
// Secure Express application with error handling & input validation
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');
const app = express();

// Security middleware
app.use(helmet()); // Add security headers
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Request logging middleware
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    handleError(res, error, 500, 'Health check failed');
  }
});

// Users endpoint with input validation
app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameters
    const { limit, offset } = req.query;

    if (limit && (!Number.isInteger(Number(limit)) || Number(limit) < 1 || Number(limit) > 100)) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100.' 
      });
    }

    if (offset && (!Number.isInteger(Number(offset)) || Number(offset) < 0)) {
      return res.status(400).json({ 
        error: 'Invalid offset parameter. Must be a non-negative integer.' 
      });
    }

    // Example user data (in production, fetch from database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const limitNum = Math.min(Number(limit) || 10, 100);
    const offsetNum = Math.max(Number(offset) || 0, 0);
    const paginatedUsers = users.slice(offsetNum, offsetNum + limitNum);

    res.json({
      data: paginatedUsers,
      total: users.length,
      limit: limitNum,
      offset: offsetNum,
    });
  } catch (error) {
    next(error);
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ 
    error: 'Not Found',
    message: `The requested endpoint ${req.method} ${req.path} does not exist.`
  });
});

// Global error handling middleware (must be last)
app.use((err, req, res, next) => {
  console.error(`[ERROR] ${new Date().toISOString()}:`, err);

  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'An internal server error occurred' 
    : err.message;

  res.status(statusCode).json({
    error: {
      message,
      statusCode,
      ...(process.env.NODE_ENV !== 'production' && { stack: err.stack })
    }
  });
});

// Helper function for error handling
function handleError(res, error, statusCode = 500, message = 'An error occurred') {
  console.error(`[${statusCode}] ${message}:`, error);
  res.status(statusCode).json({
    error: {
      message: process.env.NODE_ENV === 'production' ? message : error.message,
      statusCode
    }
  });
}

// Start server with error handling
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`[${new Date().toISOString()}] Server running on port ${PORT}`);
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('[UNCAUGHT EXCEPTION]', err);
  process.exit(1);
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('[UNHANDLED REJECTION]', reason);
  process.exit(1);
});

module.exports = app;
```

